-- Repair staff lab_id mismatch for Michael (lab_id was 3, real id is whatever staff_labs.id resolves to for user 17) --
UPDATE staff_employees
SET lab_id = (SELECT id FROM staff_labs WHERE user_id = 17 ORDER BY id LIMIT 1),
    updated_at = '2026-05-03T21:25:48Z'
WHERE user_id = 17
  AND lab_id != (SELECT id FROM staff_labs WHERE user_id = 17 ORDER BY id LIMIT 1);
UPDATE staff_competency_schedules
SET lab_id = (SELECT id FROM staff_labs WHERE user_id = 17 ORDER BY id LIMIT 1)
WHERE employee_id IN (SELECT id FROM staff_employees WHERE user_id = 17)
  AND lab_id != (SELECT id FROM staff_labs WHERE user_id = 17 ORDER BY id LIMIT 1);
UPDATE staff_roles
SET lab_id = (SELECT id FROM staff_labs WHERE user_id = 17 ORDER BY id LIMIT 1)
WHERE employee_id IN (SELECT id FROM staff_employees WHERE user_id = 17)
  AND lab_id != (SELECT id FROM staff_labs WHERE user_id = 17 ORDER BY id LIMIT 1);

