-- VeritaTrack signoffs (2 per task, with policy-grounded notes) --
DELETE FROM veritatrack_signoffs WHERE user_id=17;
INSERT INTO veritatrack_signoffs (task_id, user_id, completed_date, initials, performed_by, notes, created_at)
SELECT
  t.id, 17,
  date('now', '-' || (40 + (t.id % 50)) || ' days'),
  'MV', 'Michael Veri',
  CASE WHEN t.name = 'Levey-Jennings Chart Review' THEN 'LJ charts countersigned per VeritaPolicy QA-QC-001. Mean and SD compared to peer group, shift/trend analysis clean.' WHEN t.name = 'Critical Value Read-Back Audit' THEN 'Quarterly read-back audit closed per VeritaPolicy PRE-CRIT-001. Sample of calls reviewed, gaps coached, dashboard updated.' WHEN t.name = 'Refrigerator/Freezer Temperature Log Review' THEN 'Daily temperature logs reviewed per VeritaPolicy EQ-TEMP-001. Continuous monitoring data archived, alarm tests current.' WHEN t.name = 'Eyewash Station Inspection' THEN 'Weekly eyewash inspection current per VeritaPolicy SAF-001. Annual full activation test on schedule; documentation in safety binder.' WHEN t.name = 'Fire and Emergency Preparedness Training' THEN 'Annual emergency preparedness training closed per VeritaPolicy SAF-EMER-001. After-action notes filed; gaps assigned to safety officer.' WHEN t.name = 'Chemical Hygiene / Hazard Communication Training' THEN 'HazCom training closed per VeritaPolicy SAF-CHP-001. Labeling, secondary container, and pictogram review documented.' WHEN t.name = 'Pipette Calibration' THEN 'Pipette calibration current per VeritaPolicy EQ-PIP-001. Vendor certificate filed; instrument tag and inventory list updated.' WHEN t.name = 'Thermometer Calibration' THEN 'Annual thermometer verification current per VeritaPolicy EQ-CAL-001. Offset card placed on each unit; due dates tracked in equipment registry.' WHEN t.name = 'Centrifuge RPM Verification' THEN 'Centrifuge verification current per VeritaPolicy EQ-CAL-001. Preventive maintenance log countersigned; certificate retained in equipment folder.' WHEN t.name = 'Timer Verification' THEN 'Timer verification current per VeritaPolicy EQ-CAL-001. Labels updated, results filed with equipment binder.' WHEN t.name = 'Timer calibration ' THEN 'Timer calibration current per VeritaPolicy EQ-CAL-001. Documentation filed in equipment binder.' WHEN t.name = 'Reagent Inventory Reconciliation' THEN 'Reagent reconciliation current per VeritaPolicy SUP-INV-001. Cold-chain log clean, expired stock removed and documented.' WHEN t.name = 'Vendor Performance Review' THEN 'Vendor performance review closed per VeritaPolicy SUP-VEND-001. Discussion captured in QM meeting minutes.' WHEN t.name = 'Competency Assessment - Annual (all staff)' THEN 'Annual competency cycle closed per VeritaPolicy HR-COMP-001. Director attestation on file; remediation actions tracked.' WHEN t.category = 'QC Review' THEN 'Monthly QC review complete per VeritaPolicy QA-QC-001. Westgard rules evaluated, no out-of-control events this cycle. Bias and CV trended within manufacturer claims. Documentation filed in QC binder and scanned to shared drive.' WHEN t.category = 'Quality Assessment' THEN 'Current PT cycle closed per VeritaPolicy QA-PT-002. Director attestation signed, no PT referral, no result alteration. Remediation tracker reviewed and clean. Files staged for COLA on-site review.' WHEN t.category = 'Policy Review' THEN 'Biennial SOP review signed by laboratory director per VeritaPolicy DOC-001. Effective date and revision number updated. Superseded copy archived; current copy in active SOP binder and intranet.' WHEN t.category = 'Calibration Verification' THEN 'Calibration verification current per VeritaPolicy ANA-CALVER-001. Six-month interval met, AMR re-established, exception report empty. Documentation filed with reagent lot records.' WHEN t.category = 'Correlation' THEN 'Semi-annual correlation closed per VeritaPolicy ANA-CORR-001. Paired analyzer comparison passing across clinical decision points. Investigation memo retained with QM file.' WHEN t.category = 'Precision Verification' THEN 'Precision verification current per VeritaPolicy ANA-PERF-001. Twenty-replicate study repeated at two levels, statistics retained with validation binder.' WHEN t.category = 'Equipment Calibration' THEN 'Calibration current per VeritaPolicy EQ-CAL-001. Service tag posted on instrument, certificate filed in equipment folder, next-due date scheduled.' WHEN t.category = 'Daily Checks' THEN 'Daily temperature checks current per VeritaPolicy EQ-TEMP-001. Min/max captured, alarm function tested, log countersigned by supervisor.' WHEN t.category = 'Blood Bank Alarm Checks' THEN 'Quarterly alarm test current per VeritaPolicy BB-ALARM-001. Independent thermometer used, response time logged, calibration label updated. Record filed in blood bank QA binder.' WHEN t.category = 'Water Contamination' THEN 'Water quality current per VeritaPolicy SUP-H2O-001. CLRW specification verified, system maintenance log countersigned. Out-of-spec response plan reviewed with staff.' WHEN t.category = 'Safety' THEN 'Safety inspection closed per VeritaPolicy SAF-001. Chemical hygiene plan reviewed with staff. Findings logged on safety dashboard, no open corrective actions.' WHEN t.category = 'HIPAA' THEN 'Annual HIPAA training closed per VeritaPolicy COMP-HIPAA-001. Quiz scores retained, breach response plan reviewed, BAAs verified current.' WHEN t.category = 'Bloodborne Pathogen' THEN 'Annual BBP training closed per VeritaPolicy SAF-BBP-001. Sharps log reviewed, PPE inventory verified, post-exposure protocol re-affirmed.' WHEN t.category = 'Competency' THEN 'Annual competency closed per VeritaPolicy HR-COMP-001. Records signed by technical consultant; assessor qualifications attached; due dates rolled forward.' WHEN t.category = 'Inventory' THEN 'Inventory cycle count closed per VeritaPolicy SUP-INV-001. Par levels reset, vendor reorder triggered, cold-chain receiving log reviewed.' WHEN t.category = 'Vendor Management' THEN 'Vendor scorecard updated per VeritaPolicy SUP-VEND-001. Recall notices reconciled, contracts confirmed current, performance discussed at QM meeting.' ELSE 'Signoff current per applicable laboratory SOP (VeritaPolicy library). Documentation filed and available for surveyor review.' END,
  '2026-05-03T21:25:48Z'
FROM veritatrack_tasks t WHERE t.user_id = 17;
INSERT INTO veritatrack_signoffs (task_id, user_id, completed_date, initials, performed_by, notes, created_at)
SELECT
  t.id, 17,
  date('now', '-' || (220 + (t.id % 60)) || ' days'),
  'MV', 'Michael Veri',
  CASE WHEN t.name = 'Levey-Jennings Chart Review' THEN 'Prior LJ chart review per QC Review Policy (VeritaPolicy: QA-QC-001). Westgard 1-3s, 2-2s, R-4s, 4-1s evaluated; no run rejected.' WHEN t.name = 'Critical Value Read-Back Audit' THEN 'Prior critical value read-back audit per Communication of Critical Results Policy (VeritaPolicy: PRE-CRIT-001) and TJC NPSG.02.03.01. Read-back compliance >95%.' WHEN t.name = 'Refrigerator/Freezer Temperature Log Review' THEN 'Prior temperature log review per Storage Monitoring Policy (VeritaPolicy: EQ-TEMP-001). Excursions investigated; product impact assessment retained.' WHEN t.name = 'Eyewash Station Inspection' THEN 'Prior weekly eyewash flush per Laboratory Safety Plan (VeritaPolicy: SAF-001) and ANSI Z358.1. Flow and water clarity verified, tag initialed.' WHEN t.name = 'Fire and Emergency Preparedness Training' THEN 'Prior fire and emergency drill per Emergency Preparedness Policy (VeritaPolicy: SAF-EMER-001). Evacuation route confirmed, extinguisher use rehearsed.' WHEN t.name = 'Chemical Hygiene / Hazard Communication Training' THEN 'Prior chemical hygiene refresher per Chemical Hygiene Plan (VeritaPolicy: SAF-CHP-001) and OSHA 29 CFR 1910.1450. SDS index audited.' WHEN t.name = 'Pipette Calibration' THEN 'Prior pipette calibration per Pipette Management Policy (VeritaPolicy: EQ-PIP-001). Gravimetric verification at low/mid/high volume within ISO 8655 limits.' WHEN t.name = 'Thermometer Calibration' THEN 'Prior thermometer verification per Equipment Management Policy (VeritaPolicy: EQ-CAL-001). NIST-traceable reference compared, offset documented.' WHEN t.name = 'Centrifuge RPM Verification' THEN 'Prior centrifuge tachometer check per Equipment Management Policy (VeritaPolicy: EQ-CAL-001). RPM within +/-5%; brushes and gaskets inspected.' WHEN t.name = 'Timer Verification' THEN 'Prior timer accuracy check per Equipment Management Policy (VeritaPolicy: EQ-CAL-001). Verified against NIST time source, deviation within 1 second per minute.' WHEN t.name = 'Timer calibration ' THEN 'Prior timer calibration per Equipment Management Policy (VeritaPolicy: EQ-CAL-001). Verified against NIST time source.' WHEN t.name = 'Reagent Inventory Reconciliation' THEN 'Prior reagent reconciliation per Reagent Management Policy (VeritaPolicy: SUP-INV-001). Lot numbers, expiration dates, and storage conditions verified.' WHEN t.name = 'Vendor Performance Review' THEN 'Prior vendor scorecard reviewed per Procurement and Vendor Policy (VeritaPolicy: SUP-VEND-001). Open service tickets and CAPA tracked.' WHEN t.name = 'Competency Assessment - Annual (all staff)' THEN 'Prior annual competency window per Competency Assessment Policy (VeritaPolicy: HR-COMP-001). All six CLIA elements evaluated for testing personnel.' WHEN t.category = 'QC Review' THEN 'Reviewed prior month Levey-Jennings charts per QC SOP (VeritaPolicy: QC Review Policy QA-QC-001). Two 1-2s warnings on shift change, no rule violations requiring corrective action. Charts initialed and filed in QC binder.' WHEN t.category = 'Quality Assessment' THEN 'Prior PT event reviewed per Proficiency Testing Policy (VeritaPolicy: QA-PT-002). All graded analytes within acceptable range. Investigation log reviewed for any unsuccessful results, none open. Records retained 2 years per CLIA.' WHEN t.category = 'Policy Review' THEN 'Prior biennial SOP review completed per Document Control Policy (VeritaPolicy: DOC-001). Redlines incorporated, version stamped, training acknowledgment captured for affected staff.' WHEN t.category = 'Calibration Verification' THEN 'Prior CalVer/CVR run per Calibration Verification Policy (VeritaPolicy: ANA-CALVER-001). Three levels spanning AMR, results inside +/-10% acceptance. Records filed with method validation packet.' WHEN t.category = 'Correlation' THEN 'Prior method correlation per Method Comparison Policy (VeritaPolicy: ANA-CORR-001). Bias within total allowable error budget; Bland-Altman reviewed.' WHEN t.category = 'Precision Verification' THEN 'Prior precision study reviewed per Performance Verification Policy (VeritaPolicy: ANA-PERF-001). Within-run and between-run CV inside manufacturer claim.' WHEN t.category = 'Equipment Calibration' THEN 'Prior equipment calibration per Equipment Management Policy (VeritaPolicy: EQ-CAL-001). NIST-traceable standards used, deviation within tolerance, sticker updated.' WHEN t.category = 'Daily Checks' THEN 'Prior temperature log reviewed per Storage Monitoring Policy (VeritaPolicy: EQ-TEMP-001). All readings inside acceptable range; one excursion documented with corrective action.' WHEN t.category = 'Blood Bank Alarm Checks' THEN 'Prior alarm test per Blood Bank Storage Policy (VeritaPolicy: BB-ALARM-001) and AABB Standards. Audible and visual alarm verified at high and low set points.' WHEN t.category = 'Water Contamination' THEN 'Prior water testing per Reagent Water Quality Policy (VeritaPolicy: SUP-H2O-001) and CLSI GP40. Conductivity and microbial limits met.' WHEN t.category = 'Safety' THEN 'Prior safety drill per Laboratory Safety Plan (VeritaPolicy: SAF-001). Eyewash flushed weekly, fire extinguisher tags current, MSDS index audited.' WHEN t.category = 'HIPAA' THEN 'Prior HIPAA refresher per Privacy and Security Policy (VeritaPolicy: COMP-HIPAA-001). Workforce attestations on file, training matrix current.' WHEN t.category = 'Bloodborne Pathogen' THEN 'Prior BBP refresher per Exposure Control Plan (VeritaPolicy: SAF-BBP-001) per OSHA 29 CFR 1910.1030. Hepatitis B status documented.' WHEN t.category = 'Competency' THEN 'Prior competency assessment per Competency Assessment Policy (VeritaPolicy: HR-COMP-001). All six CLIA elements evaluated; remediation tracked where needed.' WHEN t.category = 'Inventory' THEN 'Prior inventory reconciliation per Reagent Management Policy (VeritaPolicy: SUP-INV-001). Lot-to-lot validation logged, expired stock removed.' WHEN t.category = 'Vendor Management' THEN 'Prior vendor performance review per Procurement and Vendor Policy (VeritaPolicy: SUP-VEND-001). Service tickets, response times, and CAPA closure tracked.' ELSE 'Prior signoff reviewed per applicable laboratory SOP (VeritaPolicy library). Records retained per CLIA documentation requirements.' END,
  '2026-05-03T21:25:48Z'
FROM veritatrack_tasks t WHERE t.user_id = 17;

